from __future__ import annotations

from pathlib import Path
import py_compile

ROOT_DIR = Path(r"C:\missio")

FILES = {'backend/app/core/roles.py': 'from __future__ import annotations\n\nfrom enum import StrEnum\n\n\nclass UserRole(StrEnum):\n    """Supported Missio user roles."""\n\n    SUPER_ADMIN = "super_admin"\n    BOSS = "boss"\n    MANAGER = "manager"\n    BUSINESS_OWNER = "business_owner"\n    STAFF = "staff"\n\n\nADMIN_ROLES: set[UserRole] = {\n    UserRole.SUPER_ADMIN,\n    UserRole.BOSS,\n}\n\nOPERATION_MANAGER_ROLES: set[UserRole] = {\n    UserRole.SUPER_ADMIN,\n    UserRole.BOSS,\n    UserRole.MANAGER,\n}\n\nSTAFF_VISIBLE_ROLES: set[UserRole] = {\n    UserRole.STAFF,\n}\n\nROLE_LABELS: dict[UserRole, str] = {\n    UserRole.SUPER_ADMIN: "Süper Admin",\n    UserRole.BOSS: "Patron",\n    UserRole.MANAGER: "Yönetici",\n    UserRole.BUSINESS_OWNER: "İşletme Sahibi",\n    UserRole.STAFF: "Personel",\n}\n\n\ndef get_all_role_values() -> list[str]:\n    """Return all role values as strings."""\n\n    return [role.value for role in UserRole]\n\n\ndef is_valid_role(role: str) -> bool:\n    """Return whether the given role is supported."""\n\n    return role in get_all_role_values()\n\n\ndef is_admin_role(role: str) -> bool:\n    """Return whether the given role has admin level privileges."""\n\n    if not is_valid_role(role):\n        return False\n\n    return UserRole(role) in ADMIN_ROLES\n\n\ndef can_manage_operations(role: str) -> bool:\n    """Return whether the given role can manage operational tasks."""\n\n    if not is_valid_role(role):\n        return False\n\n    return UserRole(role) in OPERATION_MANAGER_ROLES\n\n\ndef get_role_label(role: str) -> str:\n    """Return Turkish display label for the given role."""\n\n    if not is_valid_role(role):\n        return "Bilinmeyen Rol"\n\n    return ROLE_LABELS[UserRole(role)]\n', 'backend/app/core/security.py': 'from __future__ import annotations\n\nimport re\nfrom dataclasses import dataclass\n\nfrom passlib.context import CryptContext\n\n\npassword_context = CryptContext(\n    schemes=["bcrypt"],\n    deprecated="auto",\n)\n\n\n@dataclass(frozen=True)\nclass PasswordPolicy:\n    """Password policy used across Missio authentication flows."""\n\n    min_length: int = 10\n    require_uppercase: bool = True\n    require_lowercase: bool = True\n    require_digit: bool = True\n    require_special: bool = True\n\n\nDEFAULT_PASSWORD_POLICY = PasswordPolicy()\n\n\ndef hash_password(password: str) -> str:\n    """Hash a plain password using the configured password context."""\n\n    return password_context.hash(password)\n\n\ndef verify_password(plain_password: str, password_hash: str) -> bool:\n    """Verify a plain password against a stored password hash."""\n\n    return password_context.verify(plain_password, password_hash)\n\n\ndef validate_password_strength(\n    password: str,\n    policy: PasswordPolicy = DEFAULT_PASSWORD_POLICY,\n) -> list[str]:\n    """Return password validation errors. Empty list means password is valid."""\n\n    errors: list[str] = []\n\n    if len(password) < policy.min_length:\n        errors.append(f"Şifre en az {policy.min_length} karakter olmalıdır.")\n\n    if policy.require_uppercase and not re.search(r"[A-ZÇĞİÖŞÜ]", password):\n        errors.append("Şifre en az bir büyük harf içermelidir.")\n\n    if policy.require_lowercase and not re.search(r"[a-zçğıöşü]", password):\n        errors.append("Şifre en az bir küçük harf içermelidir.")\n\n    if policy.require_digit and not re.search(r"\\d", password):\n        errors.append("Şifre en az bir rakam içermelidir.")\n\n    if policy.require_special and not re.search(r"[^A-Za-z0-9ÇĞİÖŞÜçğıöşü]", password):\n        errors.append("Şifre en az bir özel karakter içermelidir.")\n\n    return errors\n\n\ndef is_password_strong(password: str) -> bool:\n    """Return whether a password satisfies the default password policy."""\n\n    return not validate_password_strength(password)\n', 'backend/app/commands/check_auth_security.py': 'from __future__ import annotations\n\nfrom app.core.roles import (\n    can_manage_operations,\n    get_all_role_values,\n    get_role_label,\n    is_admin_role,\n)\nfrom app.core.security import (\n    hash_password,\n    is_password_strong,\n    validate_password_strength,\n    verify_password,\n)\n\n\ndef check_password_hashing() -> None:\n    """Validate password hashing and verification helpers."""\n\n    sample_password = "Missio.2026!"\n    wrong_password = "Wrong.2026!"\n    password_hash = hash_password(sample_password)\n\n    if sample_password in password_hash:\n        raise RuntimeError("Hash içinde açık şifre görünüyor.")\n\n    if not verify_password(sample_password, password_hash):\n        raise RuntimeError("Doğru şifre doğrulanamadı.")\n\n    if verify_password(wrong_password, password_hash):\n        raise RuntimeError("Yanlış şifre hatalı şekilde doğrulandı.")\n\n    print("Parola hash kontrolü başarılı.")\n\n\ndef check_password_policy() -> None:\n    """Validate password policy helper."""\n\n    weak_password = "123"\n    strong_password = "Missio.2026!"\n\n    weak_errors = validate_password_strength(weak_password)\n\n    if not weak_errors:\n        raise RuntimeError("Zayıf şifre hatalı şekilde güçlü kabul edildi.")\n\n    if not is_password_strong(strong_password):\n        raise RuntimeError("Güçlü şifre hatalı şekilde reddedildi.")\n\n    print("Parola politika kontrolü başarılı.")\n    print("Zayıf şifre hata sayısı:", len(weak_errors))\n\n\ndef check_roles() -> None:\n    """Validate role definitions."""\n\n    role_values = get_all_role_values()\n\n    if "super_admin" not in role_values:\n        raise RuntimeError("super_admin rolü eksik.")\n\n    if "staff" not in role_values:\n        raise RuntimeError("staff rolü eksik.")\n\n    if not is_admin_role("super_admin"):\n        raise RuntimeError("super_admin admin rolü olarak tanınmadı.")\n\n    if is_admin_role("staff"):\n        raise RuntimeError("staff hatalı şekilde admin rolü kabul edildi.")\n\n    if not can_manage_operations("manager"):\n        raise RuntimeError("manager operasyon yönetebilir olmalı.")\n\n    print("Rol kontrolü başarılı.")\n    print("Tanımlı roller:")\n    for role in role_values:\n        print(f"- {role}: {get_role_label(role)}")\n\n\ndef main() -> None:\n    """Run all auth security checks."""\n\n    check_password_hashing()\n    check_password_policy()\n    check_roles()\n    print("Auth güvenlik temel kontrolü başarılı.")\n\n\nif __name__ == "__main__":\n    main()\n', 'backend/tests/test_security.py': 'from app.core.roles import can_manage_operations, is_admin_role, is_valid_role\nfrom app.core.security import (\n    hash_password,\n    is_password_strong,\n    validate_password_strength,\n    verify_password,\n)\n\n\ndef test_password_hash_and_verify() -> None:\n    password = "Missio.2026!"\n    password_hash = hash_password(password)\n\n    assert password not in password_hash\n    assert verify_password(password, password_hash)\n    assert not verify_password("Wrong.2026!", password_hash)\n\n\ndef test_password_policy_rejects_weak_password() -> None:\n    errors = validate_password_strength("123")\n\n    assert errors\n\n\ndef test_password_policy_accepts_strong_password() -> None:\n    assert is_password_strong("Missio.2026!")\n\n\ndef test_role_validation() -> None:\n    assert is_valid_role("super_admin")\n    assert is_valid_role("staff")\n    assert not is_valid_role("unknown_role")\n\n\ndef test_role_permissions() -> None:\n    assert is_admin_role("super_admin")\n    assert not is_admin_role("staff")\n    assert can_manage_operations("manager")\n    assert not can_manage_operations("staff")\n'}


def write_file(relative_path: str, content: str) -> None:
    target = ROOT_DIR / relative_path
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(content, encoding="utf-8")
    print(f"Yazildi: {target}")


def compile_files() -> None:
    for relative_path in FILES:
        if relative_path.endswith(".py"):
            py_compile.compile(str(ROOT_DIR / relative_path), doraise=True)

    print("Python syntax kontrolu basarili.")


def main() -> None:
    print("Missio ADIM 5A auth guvenlik temeli olusturuluyor.")
    print("")

    for relative_path, content in FILES.items():
        write_file(relative_path, content)

    compile_files()

    print("")
    print("Tamamlandi.")


if __name__ == "__main__":
    main()
